import React, { useState, useEffect } from "react";
import EmailList from "./emailList";
import {
  ReadEmail, ReadAllEmail,
  ReadSentEmail /*, GetAllEmailPagination*/,
} from "../../api/api";
const MainEmailPage = ({ email, emailId }) => {
  let [apiCall, setApiCall] = useState(false);
  let [isLoading, setIsLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [searchError, setSearchError] = useState("");
  const [emailType, setEmailType] = useState(emailId ? "SENT" : "INBOX");
  /* data and id states */
  const [emailData, setEmailData] = useState([]);
  // let [emailSing, setemailSing] = useState();
  // let [lmiaStatus, setLmiaStatus] = useState();
  /* Pagination states */
  // const [totalData, setTotalData] = useState(0);
  const [currentPage, setCurrentPage] = useState("");
  const [nextLink, setNextLink] = useState("");
  const [loadingMore, setLoadingMore] = useState(false);
  // const [pageToken, setPageToken] = useState([]);
  const [recordsPerPage] = useState(10);
  /* Shorting states */
  //   const [columnName, setcolumnName] = useState("msgno");
  //   const [sortOrder, setSortOrder] = useState("DESC");

  /* Function to get Email data*/
  const EmailData = async () => {
    if (currentPage !== "") {
      setLoadingMore(true);
    } else {
      setIsLoading(true);
    }
    if (email) {
      try {
        let userData;
        if (emailType === "ALL") {
          userData = await ReadAllEmail(
            currentPage,
            recordsPerPage,
            search,
            email?.trim("")
          );
        } else if (emailType === "SENT") {
          userData = await ReadSentEmail(
            currentPage,
            recordsPerPage,
            search,
            email?.trim("")
          );
        } else
          userData = await ReadEmail(currentPage, recordsPerPage, search, email?.trim(""));
        if (
          (userData.status === "0" ||
            userData.status === 0 ||
            userData.data.value === undefined ||
            userData.data.value.length === 0 ||
            userData.data.message === "No Mail Data Found") && !nextLink && currentPage === ""
        ) {
          setEmailData([]);
          setIsLoading(false);
          setLoadingMore(false);
          // setTotalData(0);
          // setPageToken([]);
        } else {
          let newData = userData.data.value.slice(); // Create a copy of the array
          if (currentPage === "") {
            setEmailData(newData);
          } else {
            setEmailData(prev => [...prev, ...newData]);
          }
          setNextLink(userData.data['@odata.nextLink'] || "");
          const newUrl = window.location.pathname;
          window.history.replaceState({}, document.title, newUrl);
          localStorage.setItem("navigation_url", "")
          setIsLoading(false);
          setLoadingMore(false);
          // if (emailType === "SENT") {
          //   reversedData.reverse(); // Reverse the array if emailType is "SENT"
          // }
          // setPageToken([]);
          // setTotalData(0);
          // try {
          //   let PageRes = await GetAllEmailPagination(email);
          //   setPageToken(
          //     PageRes.data.paginationData.map((item) => item.split("=")[4])
          //   );
          //   setTotalData(PageRes.data.paginationDataCount || 0);
          // } catch (err) {
          //   console.log(err);
          // }
          // setPageToken(
          //   userData.data.paginationData &&
          //     userData.data.paginationData.map((item) => item.split("=")[4])
          // );
          // setTotalData(userData.data.paginationDataCount || 0);
        }
      } catch (err) {
        console.log(err);
        setEmailData([]);
        // setTotalData(0);
        // setPageToken([]);
        setIsLoading(false);
        setLoadingMore(false);
      }
    }
  };

  /*Function to load more data while scrolling */
  let handelScroll = (e) => {
    const { scrollTop, scrollHeight, clientHeight } = e.target;
    if (scrollTop + clientHeight >= scrollHeight - 10 && nextLink && !loadingMore) {
      setCurrentPage(nextLink);
    }
  };
  
  /*Render function to get the email data*/
  useEffect(() => {
    EmailData();
    if (apiCall === true) {
      setApiCall(false);
    }
    // eslint-disable-next-line
  }, [
    currentPage,
    recordsPerPage,
    search /*, columnName, sortOrder*/,
    apiCall,
    emailType,
    email,
    emailId
  ]);

  /*Pagination Calculation */
  // const nPages = Math.ceil(totalData / recordsPerPage);

  /*Function to search the employee */
  const onSearch = (e) => {
    const inputValue = e.target.value;
    setSearch(inputValue);
    setCurrentPage("");
    setNextLink("");
    if (inputValue.length > 0) {
      if (/[-]?\d+(\.\d+)?/.test(inputValue.charAt(0))) {
        setSearchError("Employer's Name cannot start with a number.");
      } else if (!/^[A-Za-z0-9 ]*$/.test(inputValue)) {
        setSearchError("Cannot use special characters.");
      } else {
        setSearchError("");
      }
    } else {
      setSearchError("");
    }
  };
  return (
    <>
      <div className={"email_container overflow-hidden bg-default-2"}>
        <div
          className={"container-fluid document_container bg-white px-0"}
          id="dashboard-body"
          onScroll={(e) => handelScroll(e)}
        >
          <div className="mb-4 align-items-center">
            <div className={"page___heading"}>
              <h3 className="font-size-6 mb-0">Emails</h3>
            </div>
            {/* <!-- Email Search and Filter- --> */}
            {/* <div
                className={
                  userType === "company"
                    ? "d-none"
                    : "row m-0 align-items-center"
                }
              >
                <div className="col p-1 form_group mb-3">
                  <p className="input_label">Search Employee:</p>
                  <input
                    required
                    type="text"
                    className="form-control"
                    placeholder={"Search Employee"}
                    value={search}
                    name={"Employee_name"}
                    onChange={(e) => onSearch(e)}
                  />
                </div>
                <div className="col p-1 form_group mb-3">
                  <p className="input_label">Filter by Email Country:</p>
                  <div className="select_div">
                    <select
                      name="experience"
                      value={EmailCountryFilter}
                      id="experience"
                      onChange={(e) => {
                        setEmailCountryFilter(e.target.value);
                        setEmpId("");
                        setpageNo(1)
                      }}
                      className="text-capitalize form-control"
                    >
                      <option value={""}>Select Country</option>
                      {(FilterJson.location || []).map((item, i) => (
                        <option value={item} key={i}>
                          {item}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
                <div className="col p-1 form_group mb-3">
                  <p className="input_label">Filter by Email Status:</p>
                  <div className="select_div">
                    <select
                      name="status"
                      value={VisStatusFilterValue}
                      id="status"
                      onChange={(e) => {
                        setVisStatusFilterValue(e.target.value);
                        setEmpId("");
                        setpageNo(1)
                      }}
                      className="text-capitalize form-control"
                    >
                      <option value={""}>Select Email status </option>
                      <option value={"pending"}>Pending</option>
                      <option value={"approved"}>Approved</option>
                      <option value={"reject"}>Rejected</option>
                      <option value={"experied"}>experied</option>
                      <option value={"cancel"}>Cancel</option>
                    </select>
                  </div>
                </div>
                <div className="col p-1 form_group mb-3">
                  <p className="input_label">Filter by Interested In:</p>
                  <div className="select_div">
                    <select
                      name="intrested_in"
                      value={IntrestedFilterValue}
                      id="intrested_in"
                      onChange={(e) => {
                        setIntrestedFilterValue(e.target.value);
                        setEmpId("");
                        setpageNo(1)
                      }}
                      className="text-capitalize form-control"
                    >
                      <option value="" data-display="Product Designer">
                        Select Application type
                      </option>
                      {(FilterJson.interested || []).map((data, i) => {
                        return (
                          <option value={data} key={i}>
                            {data}
                          </option>
                        );
                      })}
                    </select>
                  </div>
                </div>
              </div> */}
            {/*<-- Email Search  -->*/}
            {/* <div className={"row m-0 align-items-center"}>
                  
                  <div className="col p-1 form_group mb-3">
                  <p className="input_label">Company Name:</p>
                  <input
                    required
                    type="text"
                    className="form-control w-100"
                    placeholder={"Company name"}
                    value={company}
                    name={"compnay_name"}
                    onChange={(e) => setCompany(e.target.value)}
                  />
                </div>
                <div className="col p-1 form_group mb-3">
                  <p className="input_label">Filter by Job Category:</p>
                  <div className="select_div">
                    <select
                      name="country"
                      id="country"
                      value={categoryFilterValue}
                      onChange={(e) => setCategoryFilterValue(e.target.value)}
                      className=" form-control"
                    >
                      <option value="">Job Category</option>
                      {(Json.Category || []).map((data) => {
                        return (
                          <option value={data.id} key={data.id}>
                            {data.value}
                          </option>
                        );
                      })}
                    </select>
                  </div>
                </div>
                <div className="col p-1 form_group mb-3">
                  <p className="input_label">Filter by Job Type:</p>
                  <div className="select_div">
                    <select
                      name="country"
                      id="country"
                      value={jobSwapFilterValue}
                      onChange={(e) => {
                        setJobSwapFilterValue(e.target.value);
                      }}
                      className=" form-control"
                    >
                      <option value="">Job Type</option>
                      {(FilterJson.job_type || []).map((job, i) => (
                        <option key={i} value={job}>
                          {job}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
                <div className="col p-1 form_group mb-3">
                  <p className="input_label">Filter by Job Skill:</p>
                  <div className="select_div">
                    <select
                      name="country"
                      id="country"
                      value={skillFilterValue}
                      onChange={(e) => setSkillFilterValue(e.target.value)}
                      className=" form-control"
                    >
                      <option value="">Job Skill</option>
                      {(json.skill || []).map((data) => {
                        return (
                          <option value={data.value} key={data.id}>
                            {data.value}
                          </option>
                        );
                      })}
                    </select>
                  </div>
                </div>
                <div className="col p-1 form_group mb-3">
                  <p className="input_label">Filter by Job Location:</p>
                  <div className="select_div">
                    <select
                      name="country"
                      id="country"
                      value={locationFilterValue}
                      onChange={(e) => setLocationFilterValue(e.target.value)}
                      className=" form-control"
                    >
                      <option value="">Job Location</option>
                      {(FilterJson.location || []).map((data) => {
                        return (
                          <option value={data} key={data}>
                            {data}
                          </option>
                        );
                      })}
                    </select>
                  </div>
                </div>
                </div> */}
          </div>
          <div>
            <EmailList
              apiCall={apiCall}
              setApiCall={setApiCall}
              isLoading={isLoading}
              data={emailData}
              // totalData={totalData}
              // nPages={nPages}
              currentPage={currentPage}
              // pageToken={pageToken}
              setCurrentPage={setCurrentPage}
              setEmailType={setEmailType}
              emailType={emailType}
              onSearch={onSearch}
              searcherror={searchError}
              search={search}
              email={email}
              handelScroll={handelScroll}
              EmailId={emailId}
              setNextLink={setNextLink}
            // setPageToken={setPageToken}
            />
          </div>
        </div>
      </div>
    </>
  );
};

export default MainEmailPage;
